#!/usr/bin/env python3
"""DGX DEPLOY v19.34.243 — per-entry batch gate (entry-control safety).
Fixes cap overshoot (27 vs 25, 06-02) + entry-while-paused (CEG, 06-03):
re-checks pause + (open+pending>=cap) before EVERY entry, halts the batch.
Idempotent: rewrites files, runs pytest, git commit && git push, restarts.
Run on repo root: .venv/bin/python /tmp/deploy_v19_34_243.py"""
import base64, gzip, os, subprocess, sys
FILES = {
    'backend/services/entry_gate.py': '',
    'backend/services/trading_bot_service.py': '',
    'backend/tests/test_v19_34_243_entry_gate.py': '',
}
REPO=os.getcwd()
def main():
    if not os.path.isdir(os.path.join(REPO,"backend","services")):
        print("[FATAL] not repo root"); sys.exit(1)
    for rel,b in FILES.items():
        dst=os.path.join(REPO,rel); os.makedirs(os.path.dirname(dst),exist_ok=True)
        data=gzip.decompress(base64.b64decode(b)); open(dst,"wb").write(data)
        print(f"[WROTE] {rel} ({len(data)} bytes)")
    print("[TEST] pytest v243 ...")
    r=subprocess.run([sys.executable,"-m","pytest","backend/tests/test_v19_34_243_entry_gate.py","-q"],cwd=REPO)
    if r.returncode!=0:
        print("[FATAL] pytest failed — aborting before commit/restart."); sys.exit(2)
    subprocess.run(["git","add"]+list(FILES.keys()),cwd=REPO)
    c=subprocess.run(["git","commit","-m","v19.34.243 — per-entry batch gate (cap overshoot + entry-while-paused)"],cwd=REPO)
    if c.returncode!=0: print("[INFO] commit no-op")
    p=subprocess.run(["git","push"],cwd=REPO)
    if p.returncode!=0: print("[WARN] push failed — commit is local")
    print("[RESTART] ./start_backend.sh --force")
    subprocess.run(["./start_backend.sh","--force"],cwd=REPO)
    print("[DONE] v19.34.243 deployed.")
if __name__=="__main__": main()
